import{_ as i,c as s,a,o as d}from"./app-CEcM0piI.js";const l={};function n(r,e){return d(),s("div",null,e[0]||(e[0]=[a(`<p>![[Pasted image 20240304124012.png]]</p><ul><li>序号1：表示文件、文件夹的权限控制信息</li><li>序号2：表示文件、文件夹所属用户</li><li>序号3：表示文件、文件夹所属用户组</li></ul><h3 id="序号1" tabindex="-1"><a class="header-anchor" href="#序号1"><span>序号1</span></a></h3><p>![[Pasted image 20240304124318.png]]</p><ol><li>r表示读权限</li></ol><ul><li>对文件，可以查看内容</li><li>对文件夹，可以查看文件夹内容如ls命令</li></ul><ol start="2"><li>w表示写权限</li></ol><ul><li>对文件，表示可以修改此文件</li><li>对文件夹，可以在文件夹内创建、删除、改名等操作</li></ul><ol><li>x表示执行权限</li></ol><ul><li>对文件，可以将文件作为程序执行</li><li>对文件夹，可以更改工作目录到此文件夹（cd进入）</li></ul><p>举例：drwxr-xr-x,表示：</p><ul><li>这是一个文件夹，首字母d表示</li><li>所属用户(右上角图序号2)的权限是:有r有w有x，rwx</li><li>所属用户组(右上角图序号3)的权限是:有r无w有x,r-x(-表示无此权限)</li><li>其它用户的权限是:有r无w有x，r-x</li></ul><p>s，表示set UID或set GID。位于user或group权限组的第三位置。如果在user权限组中设置了s位，则当文件被执行时，该文件是以文件所有者UID而不是用户UID 执行程序。如果在group权限组中设置了s位，当文件被执行时，该文件是以文件所有者GID而不是用户GID执行程序。 实际用户ID是创建进程的用户ID，而有效用户ID则是进程访问资源时的用户ID实际组ID是创建进程的用户主组ID，有效组ID是进程访问资源时所属的组ID</p><h2 id="chmod命令" tabindex="-1"><a class="header-anchor" href="#chmod命令"><span>chmod命令</span></a></h2><p>修改文件、文件夹的权限信息 只有文件、文件夹的所属用户或root用户可以修改</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>chmod [-R] 权限 文件或文件夹</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>-R：对文件夹内的所有内容应用同样的操作</p><p>示例： chmod u=rwx,g=rx,o=x hello.txt将文件权限修改为：rwxr-x--x其中:u表示user所属用户权限，g表示group组权限,o表示other其它用户权限 chmod -R u=rwx,g=rx,o=x test,将文件夹test以及文件夹内全部内容权限设置为:rwxr-x--x</p><p>除此之外还可以使用快捷写法： 权限可以用3位数字来代表,第一位数字表示用户权限,第二位表示用户组权限,第三位表示其它用户权限。数字的细节如下:r记为4，w记为2,x记为1,可以有：</p><ul><li>0：无任何权限，即---</li><li>1：仅有x权限，即--x</li><li>2：仅有w权限，即-w-</li><li>3：有w和x权限，即 -wx</li><li>4：仅有r权限，即r--</li><li>5：有r和x权限，即r-x</li><li>6：有r和w权限，即rw-</li><li>7：有全部权限，即 rwx</li></ul><h3 id="chown命令" tabindex="-1"><a class="header-anchor" href="#chown命令"><span>chown命令</span></a></h3><p>使用chown命令,可以修改文件、文件夹的所属用户和用户组 普通用户无法修改所属为其它用户或组，所以此命令只适用于root用户执行</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>chown [-R] [用户] [:] [用户组] 文件或文件夹</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>-R：同chmod,对文件夹内全部内容应用相同规则 用户：修改所属用户 用户组：修改所属用户组 :：用于分隔用户和用户组</p><p>示例：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>chown root hello.txt,将hello.txt所属用户修改为root</span></span>
<span class="line"><span>chown :root hello.txt,将hello.txt所属用户组修改为root</span></span>
<span class="line"><span>chown root:itheima hello.txt,将hello.txt所属用户修改为root,用户组修改为itheima</span></span>
<span class="line"><span>chown -Rroottest,将文件夹test的所属用户修改为root并对文件夹内全部内容应用同样规则</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h1 id="root用户" tabindex="-1"><a class="header-anchor" href="#root用户"><span>root用户</span></a></h1><h2 id="su切换用户" tabindex="-1"><a class="header-anchor" href="#su切换用户"><span>su切换用户</span></a></h2><p>switch user</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>su [-] 用户名</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>-：表示是否在切换用户后加载环境变量 用户名：表示要切换的用户，也可以省略，省略表示切换到root</p><p>切换用户后可以通过exit退回上一个用户，也可以使用快捷键：ctrl+d</p><p>使用普通用户切换到其他用户需要输入密码，使用root用户切换其他用户无需密码</p><h2 id="sudo临时root权限" tabindex="-1"><a class="header-anchor" href="#sudo临时root权限"><span>sudo临时root权限</span></a></h2><p>不使用root用户在执行其他命令前加sudo可以使这条命令拥有root权限</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>sudo 其他命令</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>并不是所有用户都能使用sudo，需要为普通用户配置sudo认证</p><h3 id="为普通用户配置sudo认证" tabindex="-1"><a class="header-anchor" href="#为普通用户配置sudo认证"><span>为普通用户配置sudo认证</span></a></h3><p>切换到root用户，执行visudo命令（或vi /etc/sudoers），会通过vi打开：/etc/sudoers 在文件最后添加：</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>用户名 ALL=(ALL)    NOPASSWD:ALL</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>NOPASSWD:ALL 表示使用sudo命令无需输入密码，否则每次使用sudo命令都要输入用户密码 最后要wq保存</p><h1 id="用户、用户组" tabindex="-1"><a class="header-anchor" href="#用户、用户组"><span>用户、用户组</span></a></h1><p>Linux系统可以配置多个用户、用户组 用户可以加入多个用户组中</p><p>Linux中关于权限的管控级别有两个，分别是：</p><ul><li>针对用户权限控制</li><li>针对用户组权限控制 针对某个文件，可以控制用户的权限，也可以控制用户组的权限</li></ul><h2 id="用户组操作" tabindex="-1"><a class="header-anchor" href="#用户组操作"><span>用户组操作</span></a></h2><p>都需要root用户执行</p><h3 id="groupadd创建用户组" tabindex="-1"><a class="header-anchor" href="#groupadd创建用户组"><span>groupadd创建用户组</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>groupadd 用户组名</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="groupdel删除用户组" tabindex="-1"><a class="header-anchor" href="#groupdel删除用户组"><span>groupdel删除用户组</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>groupdel 用户组名</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h2 id="用户操作" tabindex="-1"><a class="header-anchor" href="#用户操作"><span>用户操作</span></a></h2><h3 id="useradd创建用户" tabindex="-1"><a class="header-anchor" href="#useradd创建用户"><span>useradd创建用户</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>useradd [-g -d] 用户名</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>-g：指定用户的组，不指定-g，会创建同名组并自动加入，指定-g需要组已经存在，如已存在同名组，必须使用-g -d：指定用户H0ME路径，不指定，HOME目录默认在:/home/用户名</p><h3 id="userdel删除用户" tabindex="-1"><a class="header-anchor" href="#userdel删除用户"><span>userdel删除用户</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>userdel [-r] 用户名</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>-r：删除用户的HOME目录，不使用-r，删除用户时，HOME目录保留</p><h3 id="id查看用户所属组" tabindex="-1"><a class="header-anchor" href="#id查看用户所属组"><span>id查看用户所属组</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>id [用户名]</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><p>用户名：被查看的用户，如果不提供则查看自身</p><h3 id="usermod修改用户所属组" tabindex="-1"><a class="header-anchor" href="#usermod修改用户所属组"><span>usermod修改用户所属组</span></a></h3><p>将指定的用户添加到指定的组里面</p><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>usermod -aG 用户组 用户名</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div></div></div><h3 id="getent查看用户、用户组" tabindex="-1"><a class="header-anchor" href="#getent查看用户、用户组"><span>getent查看用户、用户组</span></a></h3><div class="language- line-numbers-mode" data-highlighter="shiki" data-ext="" style="--shiki-light:#393a34;--shiki-dark:#dbd7caee;--shiki-light-bg:#ffffff;--shiki-dark-bg:#121212;"><pre class="shiki shiki-themes vitesse-light vitesse-dark vp-code"><code><span class="line"><span>getent passwd 查看系统中有哪些用户</span></span>
<span class="line"><span>getent group 查看系统中有哪些用户组</span></span></code></pre><div class="line-numbers" aria-hidden="true" style="counter-reset:line-number 0;"><div class="line-number"></div><div class="line-number"></div></div></div>`,66)]))}const h=i(l,[["render",n]]),p=JSON.parse('{"path":"/base/linux/2/","title":"2 权限","lang":"zh-CN","frontmatter":{"title":"2 权限","createTime":"2025/06/18 20:42:46","permalink":"/base/linux/2/"},"readingTime":{"minutes":5.08,"words":1525},"git":{"createdTime":1750599657000,"updatedTime":1750599657000,"contributors":[{"name":"pink","username":"pink","email":"pinkdopeybug@163.com","commits":1,"avatar":"https://avatars.githubusercontent.com/pink?v=4","url":"https://github.com/pink"}]},"filePathRelative":"notes/基础/Linux/2 权限.md","headers":[]}');export{h as comp,p as data};
